post.description:
创建数据表
```
  curl -X POST 'http://{host}:{port}/api/v3/horizon/v1/table/create' \
    -H 'Content-Type: application/json' \
    -H 'api-key: api_key' \
    -H 'sensorsdata-project: default' \
    -d '{
    "project_id": 1,
    "table": {
      "db_name": "test_db",
      "name": "test_table",
      "type": "TABLE",
      "engine": "MUTABLE",
      "primary_keys": ["id"],
      "columns": [
        {
          "name": "id",
          "dw_data_type": "STRING"
        }
      ]
    }
  }'
  返回值示例：
  {
    "code": "SUCCESS",
    "request_id": "121605448c7cb6e07b463cb8c78a00d8",
    "data": {
        "workspace": "PUBLIC",
        "primary_keys": [
            "id"
        ],
        "columns": [],
        "unique_keys": [
            {
                "name": "pk_test_table",
                "columns": [
                    "id"
                ]
            }
        ],
        "type": "TABLE",
        "external": false,
        "custom_params": {},
        "business_scopes": [],
        "db_name": "test_db",
        "partition_keys": [],
        "project_id": 1,
        "engine": "MUTABLE",
        "name": "test_table",
        "direct_access_enabled": false,
        "authorization_policy": {
            "id": "_policy_#1#test_db#test_table",
            "type": "ACCESS",
            "access_policy_description": {
                "database": "test_db",
                "table": "test_table",
                "columns": [
                    "*"
                ],
                "conditions": [
                    {
                        "accounts": [
                            {
                                "id": "2",
                                "name": "admin",
                                "cname": "平台管理员",
                                "tokens": [],
                                "available": false
                            }
                        ],
                        "roles": [],
                        "duties": [],
                        "allow_permission_types": [
                            "SELECT"
                        ]
                    }
                ]
            }
        }
    }
  }
```

批量查询数据库信息
```
  curl -X POST 'http://{host}:{port}/api/v3/horizon/v1/table/public-database/list' \
    -H 'Content-Type: application/json' \
    -H 'api-key: api_key' \
    -H 'sensorsdata-project: default' \
    -d '{
    "project_id": 1
  }'
  返回值示例：
  {
    "code": "SUCCESS",
    "request_id": "121616536838406dccc1bec7f5e18495",
    "data": {
        "databases": [
            {
                "project_id": 1,
                "name": "horizon_default_1",
                "created_by": "sensorsdata.horizon",
                "workspace": "PUBLIC"
            },
            {
                "project_id": 1,
                "name": "hue_medium_table_default",
                "created_by": "sensorsdata.analytics",
                "workspace": "PUBLIC"
            },
            {
                "project_id": 1,
                "name": "horizon_workspace_default_1",
                "created_by": "sensorsdata.horizon.web",
                "workspace": "PUBLIC"
            },
            {
                "project_id": 1,
                "name": "test_db",
                "created_by": "test",
                "workspace": "PUBLIC"
            }
        ]
    }
  }
```

创建数据库
```
  curl -X POST 'http://{host}:{port}/api/v3/horizon/v1/table/public-database/create' \
    -H 'Content-Type: application/json' \
    -H 'api-key: api_key' \
    -H 'sensorsdata-project: default' \
    -d '{
    "project_id": 1,
    "database": {
      "name": "test_db",
      "created_by": "test"
    }
  }'
  返回值示例：
  {
    "code": "SUCCESS",
    "request_id": "121604079d9834d9a4011cb2b1fe588d",
    "data": {
        "workspace": "PUBLIC",
        "project_id": 1,
        "name": "test_db",
        "created_by": "test"
    }
  }
```
